// Act Completion Check - Using Act Structure Output
function checkActCompletion(items) {
  try {
    // Get the outline document
    const doc = $('Get Outline1').last().json.content;

    // Get the act structure from the previous node
    const actStructure = $('Act Structure').last().json;
    console.log("Act structure received:", JSON.stringify(actStructure, null, 2));

    // Find existing chapters
    const chapterRegex = /# Chapter (\d+):/g;
    let foundChapters = [];
    let highestExistingChapter = 0;
    let match;

    while ((match = chapterRegex.exec(doc)) !== null) {
      const chapterNum = parseInt(match[1], 10);
      foundChapters.push(chapterNum);

      if (chapterNum > highestExistingChapter) {
        highestExistingChapter = chapterNum;
      }
    }

    console.log(`Highest chapter found: ${highestExistingChapter}`);

    // Simple next chapter calculation
    const nextChapter = highestExistingChapter + 1;

    // Find which act contains the current chapter using the act structure
    let currentAct = null;

    // Use the chapterToActMap from actStructure
    const actNumber = actStructure.chapterToActMap[highestExistingChapter];
    if (actNumber) {
      currentAct = actStructure.acts.find(act => act.actNumber === actNumber);
    }

    // If we couldn't find an act (unlikely), try manual search through acts array
    if (!currentAct && actStructure.acts && actStructure.acts.length > 0) {
      for (const act of actStructure.acts) {
        if (highestExistingChapter >= act.firstChapter && highestExistingChapter <= act.lastChapter) {
          currentAct = act;
          break;
        }
      }
    }

    // If still no act found, use a default
    if (!currentAct && actStructure.acts && actStructure.acts.length > 0) {
      currentAct = actStructure.acts[0];
      console.log("Warning: Could not determine current act, using first act as default");
    } else if (!currentAct) {
      console.log("Error: No act structure available");
      return {
        json: {
          error: "No act structure available",
          currentChapter: highestExistingChapter,
          nextChapter: nextChapter
        }
      };
    }

    console.log(`Current act: ${currentAct.actNumber}, chapters ${currentAct.firstChapter}-${currentAct.lastChapter}`);

    // Check if act is complete
    const isActComplete = highestExistingChapter >= currentAct.lastChapter;

    console.log(`Is current act complete: ${isActComplete}`);
    console.log(`Next chapter: ${nextChapter}`);

    // Return values
    return {
      json: {
        actNumber: currentAct.actNumber,
        actFirstChapter: currentAct.firstChapter,
        actLastChapter: currentAct.lastChapter,
        currentChapter: highestExistingChapter,
        nextChapter: nextChapter,
        foundChapters: foundChapters,
        isComplete: isActComplete
      }
    };
  } catch (error) {
    console.log("Error:", error.message);
    return {
      json: {
        error: error.message,
        currentChapter: 0,
        nextChapter: 1,
        isComplete: false
      }
    };
  }
}

// Execute the function
return checkActCompletion($input.all());

