// Act Structure Extractor with dynamic chapter handling
function extractActStructure(items) {
  try {
    const overviewDocument = $('Get Overview').last().json.content || "";
    console.log("Overview document loaded, length:", overviewDocument.length);

    // Define base act patterns from the document structure
    const baseActPatterns = [
      { name: "ACT 1", endChapter: 7 },
      { name: "ACT 2", endChapter: 12 },
      { name: "ACT 3", endChapter: 17 }, 
      { name: "ACT 4", endChapter: 24 },
      { name: "ACT 5", endChapter: 27 }
    ];

    // Try to find the highest chapter mentioned in the overview document
    // This regex looks for any mention of "Chapter X" or similar patterns
    const chapterPattern = /Chapter\s+(\d+)|chapter\s+(\d+)/g;
    let match;
    let highestChapterInDoc = 27; // Default based on our known structure

    while ((match = chapterPattern.exec(overviewDocument)) !== null) {
      const chapterNum = parseInt(match[1] || match[2], 10);
      if (chapterNum > highestChapterInDoc) {
        highestChapterInDoc = chapterNum;
      }
    }

    console.log(`Highest chapter found in document: ${highestChapterInDoc}`);

    // Adjust act patterns if necessary
    let actPatterns = [...baseActPatterns];

    // If we found chapters beyond act 5, create additional acts
    if (highestChapterInDoc > 27) {
      // If there are additional chapters, we'll assume similar chapter counts per act
      // as in the base structure (roughly 5-7 chapters per act)
      let lastActEnd = 27;
      let nextActNumber = 6;

      while (lastActEnd < highestChapterInDoc) {
        // Calculate next act end (approximately 5-7 chapters per act)
        const nextActEnd = Math.min(lastActEnd + 6, highestChapterInDoc);

        actPatterns.push({
          name: `ACT ${nextActNumber}`,
          endChapter: nextActEnd
        });

        lastActEnd = nextActEnd;
        nextActNumber++;
      }
    }

    // Create the act structure
    const actInfo = [];
    for (let i = 0; i < actPatterns.length; i++) {
      const current = actPatterns[i];

      const startChapter = i === 0 ? 1 : actPatterns[i-1].endChapter + 1;
      const endChapter = current.endChapter;

      actInfo.push({
        actNumber: i + 1,
        title: current.name,
        firstChapter: startChapter,
        lastChapter: endChapter
      });
    }

    console.log("Final act structure:", JSON.stringify(actInfo, null, 2));

    // Create a chapter-to-act mapping
    const chapterToActMap = {};
    actInfo.forEach(act => {
      for (let i = act.firstChapter; i <= act.lastChapter; i++) {
        chapterToActMap[i] = act.actNumber;
      }
    });

    // Return the structured data
    return [{
      json: {
        acts: actInfo,
        chapterToActMap: chapterToActMap,
        totalActs: actInfo.length
      }
    }];
  } catch (error) {
    console.log("Error:", error.message);
    return [{
      json: {
        error: error.message
      }
    }];
  }
}

