// Act Completion Check - Extremely Simple Approach
function checkActCompletion(items) {
  try {
    // Get the outline document
    const doc = $('Get Outline5').last().json.content;

    // Extract act number from node name
    const nodeName = items[0]?.node?.name || '';
    console.log("Node name:", nodeName);
    const actNumberMatch = nodeName.match(/Check(\d+)/i);
    const currentActNumber = actNumberMatch ? parseInt(actNumberMatch[1], 10) : 1;

    // Get act structure for reference only
    const actStructure = $('Act Structure').last().json;
    const currentAct = actStructure.acts.find(act => act.actNumber === currentActNumber);

    // Find highest existing chapter
    const chapterRegex = /# Chapter (\d+):/g;
    let foundChapters = [];
    let highestExistingChapter = 0;
    let match;

    while ((match = chapterRegex.exec(doc)) !== null) {
      const chapterNum = parseInt(match[1], 10);
      foundChapters.push(chapterNum);

      if (chapterNum > highestExistingChapter) {
        highestExistingChapter = chapterNum;
      }
    }

    // Next chapter is ALWAYS current + 1
    const nextChapter = highestExistingChapter + 1;

    // Act completion check
    const isActComplete = currentAct && highestExistingChapter >= currentAct.lastChapter;

    console.log(`Current chapter: ${highestExistingChapter}, Next chapter: ${nextChapter}`);
    console.log(`Is Act ${currentActNumber} complete: ${isActComplete}`);

    // Return values
    return {
      json: {
        actNumber: currentActNumber,
        actFirstChapter: currentAct ? currentAct.firstChapter : null,
        actLastChapter: currentAct ? currentAct.lastChapter : null,
        currentChapter: highestExistingChapter,
        nextChapter: nextChapter, // Simply current + 1
        foundChapters: foundChapters,
        isComplete: isActComplete
      }
    };
  } catch (error) {
    console.log("Error:", error.message);
    return {
      json: {
        error: error.message,
        isComplete: false
      }
    };
  }
}

